// // This module implements a toggle switch circuit that operates on a clock signal. The output is initially set to HIGH when the reset input is activated. On each falling edge of the clock, if the reset is not active and the trigger input is LOW, the output toggles between HIGH and LOW.
module top_module(input  clk,
			  input  rst,
			  input  trigger,
			  output out);reg 				 out_reg;

   assign out = out_reg;

   always @(posedge clk)
	 if (rst)
	   out_reg <= 0;
	 else if (trigger)
	   out_reg <= ~out_reg;

endmodule
